class UnauthorizedError extends Error {
  constructor() { super('Unauthorized'); this.name = 'UnauthorizedError'; }
}

class AuthBoundary extends React.Component<{ children: ReactNode }, { error: Error | null }> {
  state = { error: null as Error | null };

  static getDerivedStateFromError(error: Error) {
    return { error };
  }

  componentDidCatch(error: Error) {
    if (error instanceof UnauthorizedError) {
      window.location.href = '/login';
      return;
    }
    Sentry.captureException(error);
  }

  render() {
    if (this.state.error && !(this.state.error instanceof UnauthorizedError)) {
      return <Error />;
    }
    if (this.state.error instanceof UnauthorizedError) return null;  // redirecting
    return this.props.children;
  }
}

